create table if not exists public.auth_rate_limit_events (id bigint generated always as identity primary key, rate_key text not null, action text not null, created_at timestamptz not null default now());
create index if not exists auth_rate_limit_events_lookup on public.auth_rate_limit_events(rate_key, action, created_at desc);
create table if not exists public.control_user_known_devices (user_id uuid not null references public.control_users(id) on delete cascade, device_hash text not null, first_seen_at timestamptz not null default now(), last_seen_at timestamptz not null default now(), primary key (user_id, device_hash));
create or replace function public.app_auth_rate_limit(p_key text, p_action text) returns jsonb language plpgsql security definer set search_path = public as $$ declare v_count int; begin delete from public.auth_rate_limit_events where created_at < now() - interval '1 hour'; select count(*) into v_count from public.auth_rate_limit_events where rate_key = p_key and action = p_action and created_at > now() - interval '15 minutes'; if v_count >= 10 then return jsonb_build_object('allowed', false); end if; insert into public.auth_rate_limit_events(rate_key, action) values (p_key, p_action); return jsonb_build_object('allowed', true); end; $$;
create or replace function public.app_public_sign_in(p_instance_key text, p_identifier text, p_pin text, p_device_hash text) returns jsonb language plpgsql security definer set search_path = public as $$ declare v_result jsonb; v_user_id uuid; v_new boolean := false; begin v_result := public.app_public_sign_in(p_instance_key, p_identifier, p_pin); if not coalesce((v_result ->> 'ok')::boolean, false) then return v_result; end if; v_user_id := (v_result -> 'profile' ->> 'id')::uuid; insert into public.control_user_known_devices(user_id, device_hash) values (v_user_id, p_device_hash) on conflict (user_id, device_hash) do update set last_seen_at = now() returning (xmax = 0) into v_new; return v_result || jsonb_build_object('new_device', v_new); end; $$;
revoke all on public.auth_rate_limit_events, public.control_user_known_devices from public, anon, authenticated;
revoke all on function public.app_public_sign_in(text, text, text) from anon, authenticated;
revoke all on function public.app_public_sign_in(text, text, text, text) from public, anon, authenticated;
revoke all on function public.app_auth_rate_limit(text, text) from public, anon, authenticated;
grant execute on function public.app_public_sign_in(text, text, text), public.app_public_sign_in(text, text, text, text), public.app_auth_rate_limit(text, text) to service_role;
